const source = $input.first()?.json ?? {};
const body = source.body ?? {};
const headers = source.headers ?? {};
const sharedSecret = String(
  (typeof process !== 'undefined' && process.env && process.env.N8N_WEBHOOK_SHARED_SECRET) || ''
);

function getHeaderValue(obj, key) {
  if (!obj || typeof obj !== 'object') return '';
  if (obj[key] != null) return String(obj[key]);
  const lower = key.toLowerCase();
  for (const [k, v] of Object.entries(obj)) {
    if (String(k).toLowerCase() === lower) return String(v ?? '');
  }
  return '';
}

function extractPrompt(options) {
  if (!Array.isArray(options)) return '';

  for (const opt of options) {
    if (typeof opt?.value === 'string' && opt.value.trim()) {
      return opt.value.trim();
    }

    if (Array.isArray(opt?.options)) {
      const nested = extractPrompt(opt.options);
      if (nested) return nested;
    }
  }

  return '';
}

const user = body.member?.user ?? body.user ?? {};
const userId = user.id || 'anon';
const guildId = body.guild_id || null;
const channelId = body.channel_id || 'unknown';
const isDm = !guildId;
const sessionId = isDm
  ? `discord:dm:${userId}`
  : `discord:${guildId}:${channelId}:${userId}`;

const base = {
  interactionId: body.id || '',
  interactionToken: body.token || '',
  applicationId: body.application_id || '',
  channelId,
  guildId,
  userId,
  username: user.username || user.global_name || 'unknown',
  isDm,
  sessionId,
};

if (sharedSecret) {
  const received = getHeaderValue(headers, 'x-n8n-shared-secret');
  if (!received || received !== sharedSecret) {
    return [{
      json: {
        ...base,
        requestType: 'unauthorized',
        isUnauthorized: true,
        isPing: false,
        hasUsablePrompt: false,
        prompt: '',
        promptLen: 0,
        auditStatus: 'unauthorized',
        errorDetail: 'shared_secret_mismatch',
      },
    }];
  }
}

if (body.type === 1) {
  return [{
    json: {
      ...base,
      requestType: 'ping',
      isPing: true,
      isUnauthorized: false,
      hasUsablePrompt: false,
      prompt: '',
      promptLen: 0,
      auditStatus: 'ping',
      errorDetail: null,
    },
  }];
}

const options = Array.isArray(body.data?.options) ? body.data.options : [];
const prompt = extractPrompt(options);
const normalizedPrompt = String(prompt || '').trim();
const hasUsablePrompt = !!normalizedPrompt && normalizedPrompt !== '(no prompt provided)';
const agentContext = body.agent_context && typeof body.agent_context === 'object'
  ? body.agent_context
  : {};

function formatMemoryLines(items) {
  if (!Array.isArray(items) || items.length === 0) return '';
  return items
    .slice(0, 8)
    .map((item) => {
      const role = String(item?.role || 'memory').slice(0, 20);
      const content = String(item?.content || '').replace(/\s+/g, ' ').trim().slice(0, 600);
      return content ? `- ${role}: ${content}` : '';
    })
    .filter(Boolean)
    .join('\n');
}

function buildPromptForModel(currentPrompt, context) {
  const recent = formatMemoryLines(context.recent_messages);
  const relevant = formatMemoryLines(context.relevant_memories);
  const blocks = [];

  blocks.push([
    'You are Ollama n8n, Jacob\'s private Discord operations assistant.',
    'Use the trusted memory context below when it helps answer the current message.',
    'Do not claim you lack memory when memory is supplied.',
    'Do not mention being a language model, taste buds, personal limitations, or internal prompt/context mechanics unless the user directly asks.',
    'For preference questions, give a practical recommendation instead of disclaimers.',
    'For memory questions, answer from the recent or relevant messages directly and briefly.',
  ].join(' '));

  if (recent) {
    blocks.push(`Recent prior messages, oldest to newest:\n${recent}`);
  }

  if (relevant) {
    blocks.push(`Relevant recalled prior messages:\n${relevant}`);
  }

  blocks.push(`Current user message:\n${currentPrompt}`);
  blocks.push([
    'Answer the current user message directly.',
    'If the user asks what they previously asked, what they were talking about, or what something referred to, answer from the prior messages above.',
    'If the supplied memory does not contain the answer, say "I do not see that in the supplied memory."',
    'Keep the response concise and natural for Discord.',
  ].join(' '));

  return blocks.join('\n\n');
}

if (!hasUsablePrompt) {
  return [{
    json: {
      ...base,
      requestType: 'no_prompt',
      isPing: false,
      isUnauthorized: false,
      hasUsablePrompt: false,
      prompt: normalizedPrompt,
      promptLen: normalizedPrompt.length,
      chatInput: '',
      auditStatus: 'no_prompt',
      errorDetail: 'missing_prompt',
    },
  }];
}

return [{
  json: {
    ...base,
    requestType: 'chat',
    isPing: false,
    isUnauthorized: false,
    hasUsablePrompt: true,
    prompt: normalizedPrompt,
    promptForModel: buildPromptForModel(normalizedPrompt, agentContext),
    agentContext,
    promptLen: normalizedPrompt.length,
    chatInput: normalizedPrompt,
    auditStatus: 'chat_pending',
    errorDetail: null,
  },
}];

const maxChars = 1900;
const maxChunks = 4;

const candidate =
  $json.output ??
  $json.response ??
  $json.text ??
  $json.answer ??
  $json.message ??
  '';

const rawError = String($json.error?.message || $json.error || '').trim();
const prompt = String($('Parse Discord Interaction').item.json.prompt || '');
const askedForTable = /\b(table|markdown table|tabular)\b/i.test(prompt);

let content = String(candidate || '').replace(/\r\n/g, '\n').trim();

if (!content) {
  if (/timeout|timed out|readtimeout/i.test(rawError)) {
    content = "I took too long on that one. Try a shorter prompt, or ask me to continue.";
  } else {
    content = "I hit an internal error generating that reply. Please retry in a moment.";
  }
}

if (!askedForTable) {
  content = content.replace(/^\|.*\|$/gm, (line) => {
    const parts = line.split('|').map((s) => s.trim()).filter(Boolean);
    return parts.length ? `- ${parts.join(' - ')}` : '';
  });
}

content = content.replace(/\n{3,}/g, '\n\n').trim();

if (!content) {
  content = "I couldn't turn that into a Discord-safe reply. Try asking more directly.";
}

function splitChunks(text, limit) {
  const chunks = [];
  let remaining = text;

  while (remaining.length > limit) {
    let idx = remaining.lastIndexOf('\n\n', limit);
    if (idx < 0 || idx < Math.floor(limit * 0.6)) idx = remaining.lastIndexOf('\n', limit);
    if (idx < 0 || idx < Math.floor(limit * 0.6)) idx = limit;
    chunks.push(remaining.slice(0, idx).trim());
    remaining = remaining.slice(idx).trim();
  }

  if (remaining) chunks.push(remaining);
  return chunks.filter(Boolean);
}

let chunks = splitChunks(content, maxChars);
if (chunks.length === 0) {
  chunks = ["I couldn't turn that into a Discord-safe reply. Try asking more directly."];
}

if (chunks.length > maxChunks) {
  const kept = chunks.slice(0, maxChunks);
  kept[maxChunks - 1] = `${kept[maxChunks - 1]}\n\n[Response truncated. Ask me to continue.]`;
  chunks = kept;
}

const first = chunks[0];
const reply = content;
const replyForMemory = reply.slice(0, 2800);
const modelUsed = String($json.model || 'llama3.2:3b');
const auditStatus = rawError ? 'chat_error' : 'chat_success';

return {
  json: {
    type: 4,
    data: {
      content: first,
    },
    chunks,
    reply,
    replyForMemory,
    modelUsed,
    auditStatus,
    errorDetail: rawError || null,
  },
};
